import { Injectable } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Observable } from 'rxjs';

@Injectable({
  providedIn: 'root'
})
export class LoggingService {
  private apiUrl = 'https://m1jp17h33i.execute-api.eu-west-2.amazonaws.com/default/LinkSelection';

  constructor(private http: HttpClient) {}

  // When button is clicked
  logButtonClick(buttonClicked: string): Observable<any> {
    const data = { buttonClicked };

    // Convert to JSON format
    const lambdaPayload = {
      body: JSON.stringify(data),
    };

    return this.http.post(this.apiUrl, lambdaPayload);
  }
}


// Prepare data in JSON string
const body = JSON.stringify({
  name: this.buttonClicked
});
const jsonData = JSON.stringify(body);
console.log(jsonData);

// API POST Request
this.http.post('https://9h3992v7k1.execute-api.eu-west-2.amazonaws.com/default/ContactForm', body)
  .subscribe(
    (response) => {
      console.log('API Response:', response);
      this.submitted = true;
      this.formErrors = false;
      this.successMessage = true;
      this.popupControlService.closePopupAfterDelay(2000);
    },
    (error) => {
      console.error('API Error:', error);
    }
  );
